import socket
import json

# Define the server address and port
SERVER_ADDRESS = '0.0.0.0'
SERVER_PORT = 12345

# Create a UDP socket
server_socket = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)

# Bind the socket to the server address and port
server_socket.bind((SERVER_ADDRESS, SERVER_PORT))

print(f"Server is listening on {SERVER_ADDRESS}:{SERVER_PORT}")

# Sample game state data
game_state = {
    "players": [
        {"id": 1, "name": "Player1", "score": 10},
        {"id": 2, "name": "Player2", "score": 5}
    ],
    "state": "running"
}

# Function to handle incoming queries
def handle_query(data, addr):
    response = json.dumps(game_state)
    server_socket.sendto(response.encode(), addr)

# Main loop to receive and process queries
while True:
    data, addr = server_socket.recvfrom(1024)  # Buffer size is 1024 bytes
    print(f"Received query from {addr}")
    handle_query(data, addr)